// Check prerequisites for YouTube upload.
// Requires:
//   - ENABLE_YOUTUBE_UPLOAD === 'true'
//   - render_video_asset.status === 'completed'
//   - render_video_asset.video_url present
//   - youtube_metadata present with title and description
//
// When prerequisites are not met, the module skips gracefully
// and returns skip_reason for logging.

const ctx = $input.first().json;

const enableUpload = $vars.ENABLE_YOUTUBE_UPLOAD || 'false';
if (enableUpload !== 'true') {
  return [{ json: { ...ctx, youtube_upload_skipped: true, skip_reason: 'ENABLE_YOUTUBE_UPLOAD is not true' } }];
}

const render = ctx.render_video_asset;
if (!render || render.status !== 'completed' || !render.video_url) {
  const reason = !render
    ? 'render_video_asset is missing'
    : render.status !== 'completed'
      ? `render_video_asset.status is '${render.status}', expected 'completed'`
      : 'render_video_asset.video_url is missing';
  return [{ json: { ...ctx, youtube_upload_skipped: true, skip_reason: reason } }];
}

const meta = ctx.youtube_metadata;
if (!meta || !meta.title || !meta.description) {
  return [{ json: { ...ctx, youtube_upload_skipped: true, skip_reason: 'youtube_metadata is missing or incomplete' } }];
}

return [{ json: { ...ctx, youtube_upload_skipped: false } }];

// Log the skip and return context with null video ID.
const ctx = $input.first().json;
return [{
  json: {
    ...ctx,
    youtube_video_id: null,
    youtube_upload_status: 'skipped',
    youtube_upload_error: ctx.skip_reason || 'Upload prerequisites not met'
  }
}];

parameters.jsonBody:
={{ (() => {
  const ctx = $('Check Upload Prerequisites').first().json;
  const meta = ctx.youtube_metadata;
  const visibility = meta.visibility || $vars.YOUTUBE_DEFAULT_VISIBILITY || 'public';
  const categoryId = $vars.YOUTUBE_CATEGORY_ID || '25';
  return {
    snippet: {
      title: meta.title,
      description: meta.description,
      tags: meta.tags || [],
      categoryId: categoryId
    },
    status: {
      privacyStatus: visibility,
      selfDeclaredMadeForKids: false
    }
  };
})() }}

