// Extract the resumable upload URL from the Location header.
// The YouTube Data API v3 returns the upload URI in the Location header
// of the 200 response to the initial resumable upload request.
const response = $input.first().json;
const uploadUrl = response?.headers?.location
  || response?.Location
  || response?.location;

if (!uploadUrl) {
  throw new Error('YouTube resumable upload initiation did not return a Location header. Response: ' + JSON.stringify(response).slice(0, 500));
}

return [{ json: { upload_url: uploadUrl } }];

// Extract the YouTube video ID from the upload response.
// The YouTube Data API returns the full video resource on successful upload.
const ctx = $('Check Upload Prerequisites').first().json;
const uploadResponse = $input.first().json;

const videoId = uploadResponse?.id;
if (!videoId) {
  throw new Error('YouTube upload response did not contain a video ID. Response: ' + JSON.stringify(uploadResponse).slice(0, 500));
}

const visibility = ctx.youtube_metadata?.visibility || 'public';

return [{
  json: {
    ...ctx,
    youtube_video_id: videoId,
    youtube_upload_status: 'published',
    youtube_upload_error: null,
    youtube_visibility: visibility
  }
}];

